/**
 * x402-stellar — Keypair client
 *
 * A fetch-compatible wrapper that automatically handles x402 payment challenges
 * using a Stellar Keypair. Designed for server-to-server calls and AI agents.
 */
import { Keypair, TransactionBuilder } from "@stellar/stellar-sdk";
import { HEADERS, X402_VERSION } from "../constants.js";
import type {
  KeypairClientConfig,
  StellarPaymentPayload,
  StellarPaymentRequired,
  StellarPaymentRequirements,
} from "../types.js";
import { decodeHeader, encodeHeader, safeDecodeHeader } from "../utils.js";
import { buildPaymentTransaction } from "./transaction.js";

// ── x402Fetch ─────────────────────────────────────────────────────────────────

/**
 * Create a fetch-compatible function that automatically pays x402 challenges
 * on Stellar using a Keypair.
 *
 * Supports XLM and USDC payments. Designed for AI agents and server-to-server
 * use cases where you control the signing key.
 *
 * @example
 * ```ts
 * import { x402Fetch } from 'x402-stellar';
 * import { Keypair } from '@stellar/stellar-sdk';
 *
 * const fetch = x402Fetch({
 *   keypair: Keypair.fromSecret('SXXXXX...'),
 *   network: 'testnet',
 * });
 *
 * const res = await fetch('https://api.example.com/premium');
 * const data = await res.json();
 * ```
 */
export function x402Fetch(config: KeypairClientConfig): typeof fetch {
  const { keypair, network, horizonUrl } = config;

  return async (input: RequestInfo | URL, init?: RequestInit): Promise<Response> => {
    const request = new Request(input, init);

    // ── First attempt (no payment) ─────────────────────────────────────────
    const firstResponse = await globalThis.fetch(request.clone());

    if (firstResponse.status !== 402) {
      return firstResponse;
    }

    // ── Parse 402 response ─────────────────────────────────────────────────
    const paymentRequiredHeader = firstResponse.headers.get(HEADERS.PAYMENT_REQUIRED);
    if (!paymentRequiredHeader) {
      // 402 without x402 header — not an x402 endpoint
      return firstResponse;
    }

    const paymentRequired = safeDecodeHeader<StellarPaymentRequired>(paymentRequiredHeader);
    if (!paymentRequired?.accepts?.length) {
      return firstResponse;
    }

    // ── Find a Stellar requirement we can satisfy ──────────────────────────
    const requirements = findStellarRequirement(paymentRequired.accepts);
    if (!requirements) {
      throw new Error(
        "x402: No compatible Stellar payment requirement found in 402 response",
      );
    }

    // ── Build and sign the payment transaction ─────────────────────────────
    const txXdr = await buildPaymentTransaction(
      {
        sourcePublicKey: keypair.publicKey(),
        payTo: requirements.payTo,
        asset: resolveAsset(requirements.asset, requirements.network),
        amountBaseUnits: requirements.maxAmountRequired,
        network,
        horizonUrl,
        maxTimeoutSeconds: requirements.maxTimeoutSeconds,
      },
      async (unsignedXdr, networkPassphrase) => {
        const tx = TransactionBuilder.fromXDR(unsignedXdr, networkPassphrase);
        tx.sign(keypair);
        return tx.toEnvelope().toXDR("base64");
      },
    );

    // ── Build X-PAYMENT payload ────────────────────────────────────────────
    const paymentPayload: StellarPaymentPayload = {
      x402Version: X402_VERSION,
      scheme: "exact",
      network: requirements.network,
      payload: { transaction: txXdr },
    };

    // ── Retry request with X-PAYMENT header ───────────────────────────────
    const retryHeaders = new Headers(init?.headers);
    retryHeaders.set(HEADERS.X_PAYMENT, encodeHeader(paymentPayload));

    return globalThis.fetch(input, { ...init, headers: retryHeaders });
  };
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function findStellarRequirement(
  accepts: StellarPaymentRequirements[],
): StellarPaymentRequirements | undefined {
  return accepts.find(
    (r) => r.scheme === "exact" && r.network.startsWith("stellar:"),
  );
}

/**
 * Resolve the on-chain asset identifier to a human-friendly alias.
 * "native" → "XLM", anything else → "USDC" (only two supported assets).
 */
function resolveAsset(
  onChainAsset: string,
  _network: string,
): "XLM" | "USDC" {
  return onChainAsset === "native" ? "XLM" : "USDC";
}
