/**
 * Stellar transaction builder for x402 payments.
 *
 * Builds signed payment transactions (XLM or USDC via Soroban) that can be
 * included as the `payload.transaction` field of a StellarPaymentPayload.
 */
import {
  Asset,
  BASE_FEE,
  Contract,
  Networks,
  Operation,
  TransactionBuilder,
  nativeToScVal,
  xdr,
} from "@stellar/stellar-sdk";
import { Horizon } from "@stellar/stellar-sdk";
import { HORIZON_URLS, NETWORK_PASSPHRASES, USDC_CONTRACT_IDS } from "../constants.js";
import type { BuildTransactionOptions, StellarNetworkAlias } from "../types.js";
import { baseUnitsToXlmString } from "../utils.js";

// ── Build a signed payment transaction XDR ────────────────────────────────────

/**
 * Build and sign a Stellar payment transaction.
 * Returns base64-encoded XDR ready to include in the x402 payload.
 *
 * Supports:
 *  - XLM (native): standard payment operation
 *  - USDC: Soroban SEP-41 token transfer invocation
 */
export async function buildPaymentTransaction(
  opts: BuildTransactionOptions,
  sign: (txXdr: string, networkPassphrase: string) => Promise<string>,
): Promise<string> {
  const {
    sourcePublicKey,
    payTo,
    asset,
    amountBaseUnits,
    network,
    horizonUrl = HORIZON_URLS[network],
    maxTimeoutSeconds,
  } = opts;

  const networkPassphrase = NETWORK_PASSPHRASES[network];
  const server = new Horizon.Server(horizonUrl);
  const account = await server.loadAccount(sourcePublicKey);

  let txBuilder: TransactionBuilder;

  if (asset === "XLM") {
    const xlmAmount = baseUnitsToXlmString(amountBaseUnits);
    txBuilder = new TransactionBuilder(account, {
      fee: BASE_FEE,
      networkPassphrase,
    })
      .addOperation(
        Operation.payment({
          destination: payTo,
          asset: Asset.native(),
          amount: xlmAmount,
        }),
      )
      .setTimeout(maxTimeoutSeconds);
  } else {
    // USDC via Soroban SEP-41 transfer
    const contractId = USDC_CONTRACT_IDS[network];
    const contract = new Contract(contractId);

    txBuilder = new TransactionBuilder(account, {
      fee: BASE_FEE,
      networkPassphrase,
    })
      .addOperation(
        contract.call(
          "transfer",
          nativeToScVal(sourcePublicKey, { type: "address" }),
          nativeToScVal(payTo, { type: "address" }),
          nativeToScVal(BigInt(amountBaseUnits), { type: "i128" }),
        ),
      )
      .setTimeout(maxTimeoutSeconds);
  }

  const tx = txBuilder.build();
  const txXdr = tx.toEnvelope().toXDR("base64");

  // Sign (implementation provided by caller — keypair or Freighter)
  return sign(txXdr, networkPassphrase);
}

/**
 * Returns the horizon URL for the given network.
 */
export function getHorizonUrl(network: StellarNetworkAlias): string {
  return HORIZON_URLS[network];
}
